={{
  (() => {
    let dateStr = $json.query.date;
    let timeStr = $json.query.time;

    // Extract date part if it includes time
    if (dateStr.includes('T')) {
      dateStr = dateStr.split('T')[0];
    }

    // Normalize time string to HH:MM:SS format
    const timeParts = timeStr.split(':');
    if (timeParts.length === 2) {
      timeStr = timeStr + ':00';
    }

    // Create ISO 8601 UTC datetime string
    const isoDateTime = dateStr + 'T' + timeStr + 'Z';

    // Create Date object to extract parts
    const date = new Date(isoDateTime);

    // Function to get ordinal suffix
    const getOrdinal = (n) => {
      const s = ["th", "st", "nd", "rd"];
      const v = n % 100;
      return n + (s[(v - 20) % 10] || s[v] || s[0]);
    };

    // Format hour/minute as "8:00 AM" or "4:30 PM"
    const formatTime12 = (h, m) => {
      const period = h >= 12 ? 'PM' : 'AM';
      const h12 = h % 12 || 12;
      const mStr = (m < 10 ? '0' : '') + m;
      return h12 + ':' + mStr + ' ' + period;
    };

    // Given UTC timestamp and offset in hours, return formatted local time
    const localTimeAtOffset = (utcDate, offsetHours) => {
      const t = utcDate.getTime() + offsetHours * 60 * 60 * 1000;
      const d = new Date(t);
      return formatTime12(d.getUTCHours(), d.getUTCMinutes());
    };

    const day = date.getUTCDate();

    // Timezone offsets (hours from UTC) and display names
    const zones = [
      { key: 'pst', offset: -8, label: 'PST (Pacific Standard Time)' },
      { key: 'pdt', offset: -7, label: 'PDT (Pacific Daylight Time)' },
      { key: 'est', offset: -5, label: 'EST (Eastern Standard Time)' },
      { key: 'bst', offset: 1, label: 'BST (British Summer Time)' },
      { key: 'cest', offset: 2, label: 'CEST (Central European Summer Time)' }
    ];

    const timeZones = {};
    const timeZonesLines = [];
    for (const z of zones) {
      const timeStr = localTimeAtOffset(date, z.offset);
      timeZones[z.key] = timeStr;
      timeZonesLines.push('• ' + timeStr + ' ' + z.label);
    }

    return {
      dayofweek: date.getUTCDay(),
      dayofweekname: ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'][date.getUTCDay()],
      day: day,
      ordinal: getOrdinal(day),
      month: date.getUTCMonth() + 1,
      monthname: ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'][date.getUTCMonth()],
      year: date.getUTCFullYear(),
      hour: date.getUTCHours(),
      minute: date.getUTCMinutes(),
      second: date.getUTCSeconds(),
      isoDateTime: isoDateTime,
      timeZones: timeZones,
      timeZonesText: timeZonesLines.join('\\n')
    };
  })()
}}

parameters.jsCode:
const item = $input.first().json;
const d = item.utcDate;
const q = item.query;
const blocks = {
  blocks: [
    { type: 'section', text: { type: 'mrkdwn', text: `<!here> Reminder: ISPO Working Group call happens ${d.dayofweekname} at ${q.time} UTC :tada:\n\nThis is an excellent meeting for newcomers looking to learn about InnerSource. All are welcome to join!` } },
    { type: 'divider' },
    { type: 'section', text: { type: 'mrkdwn', text: `*This meeting's topic:*\n\n${q.topic}` } },
    { type: 'divider' },
    { type: 'section', fields: [
      { type: 'mrkdwn', text: `:spiral_calendar_pad: *Date:*\n${d.dayofweekname}, ${d.monthname} ${d.ordinal}` },
      { type: 'mrkdwn', text: ':alarm_clock: *Time:*\nMultiple time zones below' }
    ] },
    { type: 'section', text: { type: 'mrkdwn', text: `*Time Zones:*\n${d.timeZonesText}` } },
    { type: 'divider' },
    { type: 'section', text: { type: 'mrkdwn', text: `:link: <${q.meeting_notes_url}>\n:link: <https://innersourcecommons.org/calendar/|InnerSource Commons Calendar>` } },
    { type: 'actions', elements: [ { type: 'button', text: { type: 'plain_text', text: 'Join Meeting', emoji: true }, url: 'https://us06web.zoom.us/j/84987611486?pwd=Biw6cc9UwWI6FrM51Ugox10sClIP6n.1', style: 'danger' } ] }
  ]
};
return [{ json: { ...item, blocks } }];
